"const fs = require('fs');
const path = require('path');

const BACKUP_DIR = 'D:\\000_UNSU\\z_history';

function cleanupOldBackups(targetFolder, prefix, ext, maxFiles = 5) {
  try {
    if (!fs.existsSync(targetFolder)) {
      console.log('Folder does not exist:', targetFolder);
      return;
    }

    const files = fs.readdirSync(targetFolder);
    console.log('All files in folder:', files);
    const backups = files.filter(f => {
      if (prefix === 'chat_log_') {
        return f.startsWith('chat_log_') && f.endsWith('.jsonl');
      }
      const baseName = path.basename(f, ext);
      return f.startsWith(prefix) && f.endsWith(ext) && f !== `${prefix}${ext}`;
    });

    console.log('Filtered backups:', backups);
    console.log('Backups count:', backups.length);

    if (backups.length <= maxFiles) {
      console.log('Backups count is <= maxFiles, skipping cleanup.');
      return;
    }

    backups.sort();
    console.log('Sorted backups:', backups);

    const filesToDelete = backups.slice(0, backups.length - maxFiles);
    console.log('Files to delete:', filesToDelete);
    for (const file of filesToDelete) {
      const filePath = path.join(targetFolder, file);
      if (fs.existsSync(filePath)) {
        // fs.unlinkSync(filePath);
        console.log(`[Dry Run Cleanup] Would delete: ${file}`);
      }
    }
  } catch (err) {
    console.error(`[Cleanup Error] Failed to run garbage collection on ${prefix}:`, err.message);
  }
}

cleanupOldBackups(path.join(BACKUP_DIR, 'chat_logs'), 'chat_log_', '.jsonl', 5);
cleanupOldBackups(BACKUP_DIR, 'implementation_plan', '.md', 10);
cleanupOldBackups(BACKUP_DIR, 'walkthrough', '.md', 10);
cleanupOldBackups(BACKUP_DIR, 'task', '.md', 10);
"

