"# Clean up chat logs in z_history/chat_logs (keep latest 5)
$chatLogsDir = "D:\000_UNSU\z_history\chat_logs"
if (Test-Path $chatLogsDir) {
    $files = Get-ChildItem $chatLogsDir -Filter "chat_log_*.jsonl" | Sort-Object Name
    if ($files.Count -gt 5) {
        $filesToDelete = $files | Select-Object -First ($files.Count - 5)
        foreach ($f in $filesToDelete) {
            Remove-Item $f.FullName -Force
            Write-Host "Deleted chat log backup: $($f.Name)"
        }
    }
}

# Clean up other markdown artifacts in z_history (keep latest 5 for each type)
$historyDir = "D:\000_UNSU\z_history"
$prefixes = @("implementation_plan", "walkthrough", "detail_functional_spec", "business_operations_workflow", "task")
foreach ($prefix in $prefixes) {
    if (Test-Path $historyDir) {
        $files = Get-ChildItem $historyDir -Filter "$prefix*.md" | Where-Object { $_.Name -match "^$prefix\d{8}\.md$" } | Sort-Object Name
        if ($files.Count -gt 5) {
            $filesToDelete = $files | Select-Object -First ($files.Count - 5)
            foreach ($f in $filesToDelete) {
                Remove-Item $f.FullName -Force
                Write-Host "Deleted artifact backup: $($f.Name)"
            }
        }
    }
}
