          time: `대기 ${z.wait_minutes}분`,
          detail: z.description
        }));
      }

      if (eventsRes.ok) {
        const eventsData = await eventsRes.json();
        // Append events as hot zones
        const eventZones = eventsData.map((ev: any, idx: number) => ({
          id: 100 + idx,
          name: ev.location,
          status: '수요 폭증 예상',
          time: `행사 종료 ${ev.endTime}`,
